void nw_kernel1_block(int* reference_d, int* input_itemsets_d, int cols, int penalty, int blk, int worksize, int offset_r, int offset_c, int bx) {
	int b_index_x = bx;
	int b_index_y = blk - 1 - bx;
	int base = offset_r * cols + offset_c;

	int index_base = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

	int input_local[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
	int reference_local[BLOCK_SIZE * BLOCK_SIZE];

#define SCORE(i, j) input_local[(j) + (i) * (BLOCK_SIZE + 1)]
#define REF(i, j) reference_local[(j) + (i) * BLOCK_SIZE]

	// Load initial values
	SCORE(0, 0) = input_itemsets_d[index_base];
	for (int tx = 0; tx < BLOCK_SIZE; tx++) {
		SCORE(tx + 1, 0) = input_itemsets_d[index_base + (cols)*tx];
		SCORE(0, tx + 1) = input_itemsets_d[index_base + 1 + tx];
		for (int ty = 0; ty < BLOCK_SIZE; ty++) {
			REF(ty, tx) = reference_d[index_base + cols * ty + 1 + tx];
		}
	}

	// Compute upper-left matrix
	for (int m = 0; m < BLOCK_SIZE; m++) {
		for (int tx = 0; tx <= m; tx++) {
			int t_index_x = tx + 1;
			int t_index_y = m - tx + 1;
			SCORE(t_index_y, t_index_x) = maximum(
				SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
				SCORE(t_index_y, t_index_x - 1) - penalty,
				SCORE(t_index_y - 1, t_index_x) - penalty);
		}
	}

	for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
		for (int tx = 0; tx <= m; tx++) {
			int t_index_x = tx + BLOCK_SIZE - m;
			int t_index_y = BLOCK_SIZE - tx;
			SCORE(t_index_y, t_index_x) = maximum(
				SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
				SCORE(t_index_y, t_index_x - 1) - penalty,
				SCORE(t_index_y - 1, t_index_x) - penalty);
		}
	}

	// Write back results
	for (int ty = 0; ty < BLOCK_SIZE; ty++) {
		for (int tx = 0; tx < BLOCK_SIZE; tx++) {
			input_itemsets_d[index_base + cols * ty + tx + 1] = SCORE(ty + 1, tx + 1);
		}
	}

#undef SCORE
#undef REF
}

